define("format_selfstudy/navigation", ["exports"], function(exports) {
    Object.defineProperty(exports, "__esModule", {value: true});
    exports.init = void 0;

/**
 * Adds simple previous/map/next navigation to activity pages.
 *
 * @module format_selfstudy/navigation
 */
const init = (config) => {
    if (window.self !== window.top) {
        return;
    }

    const body = document.body;
    if (!body) {
        return;
    }
    if (config.learningmapMode) {
        initLearningmapFullscreen(config);
        return;
    }
    if (body.classList.contains('path-mod-learningmap') ||
            window.location.pathname.indexOf('/mod/learningmap/') !== -1) {
        return;
    }

    const previousUrl = config.previousUrl || null;
    const nextUrl = config.nextUrl || null;
    const showNavigation = config.showNavigation !== false;
    const mapBackgroundUrl = config.mapBackgroundUrl || null;
    const pathOutline = config.showPathOutline === false ? [] :
        (Array.isArray(config.pathOutline) ? config.pathOutline : []);
    config.pathPointColor = normaliseHexColor(config.pathPointColor || '#6f1ab1');
    config.nextButtonColor = normaliseHexColor(config.nextButtonColor || config.pathPointColor);
    applyBaseExperienceColours(config);
    initAccessibleOutlineKeyboard();
    hideActivityCompletionNotice();
    alignActivityIconWithTitle();

    if (!mapBackgroundUrl && !pathOutline.length &&
            (!showNavigation || (!previousUrl && !nextUrl && !config.mapUrl))) {
        return;
    }

    const main = document.querySelector('[role="main"]');
    if (body.id === 'page-course-view-selfstudy') {
        return;
    }
    if (main && pathOutline.length && !mapBackgroundUrl) {
        renderActivityPath(main, config, pathOutline);
    }
    if (main && pathOutline.length && !mapBackgroundUrl) {
        renderPathContinueButton(main, config, pathOutline);
    }
    const hasPathContinueNavigation = !!document.querySelector('.format-selfstudy-pathcontinue');
    const nav = document.createElement('nav');
    nav.className = 'format-selfstudy-activitynav';
    nav.setAttribute('aria-label', 'Lernnavigation');

    const addButton = (label, href, variant) => {
        if (!href) {
            return;
        }
        const link = document.createElement('a');
        link.className = `btn ${variant}`;
        link.href = href;
        link.textContent = label;
        if (variant === 'btn-primary') {
            applyPrimaryButtonColour(link, config.nextButtonColor || config.pathPointColor);
        }
        nav.appendChild(link);
    };

    if (showNavigation) {
        if (config.showPreviousButton !== false) {
            addButton(config.previousLabel || 'Zurück', previousUrl, 'btn-secondary');
        }
        addButton(config.courseLabel || 'Zum Kurs', config.courseUrl, 'btn-secondary');
        if (config.showMapButton !== false) {
            addButton(config.mapLabel || 'Zur Lernlandkarte', config.mapUrl, 'btn-secondary');
        }
        if (config.customButtonLabel && config.customButtonUrl) {
            addButton(config.customButtonLabel, config.customButtonUrl, 'btn-secondary');
        }
        if (config.showNextButton !== false) {
            addButton(config.nextLabel || 'Weiter', nextUrl, 'btn-primary');
        }
    }

    if (mapBackgroundUrl && main && !document.querySelector('.format-selfstudy-gamemap-stage')) {
        const stage = document.createElement('div');
        stage.className = 'format-selfstudy-gamemap-stage';
        stage.setAttribute('aria-hidden', 'true');

        const iframe = document.createElement('iframe');
        iframe.className = 'format-selfstudy-gamemap-frame';
        iframe.src = mapBackgroundUrl;
        iframe.tabIndex = -1;
        iframe.setAttribute('loading', 'lazy');
        iframe.setAttribute('title', '');
        iframe.addEventListener('load', () => {
            applyGamemapFrameLayout(iframe, config);
        });

        stage.appendChild(iframe);
        document.body.prepend(stage);
        document.body.classList.add('format-selfstudy-gamemap-mode');

        const pageHeader = document.querySelector('#page-header');
        const secondaryNavigation = document.querySelector('.secondary-navigation') ||
            findSecondaryNavigation(pageHeader, main);

        main.classList.add('format-selfstudy-activity-popover');
        if (showNavigation) {
            main.prepend(nav);
        }

        if (secondaryNavigation) {
            secondaryNavigation.classList.add('format-selfstudy-popover-secondarynav');
            if (showNavigation) {
                nav.insertAdjacentElement('afterend', secondaryNavigation);
            } else {
                main.prepend(secondaryNavigation);
            }
        }

        return;
    }

    const anchor = document.querySelector('#page-header') || main;
    if (anchor && !hasPathContinueNavigation) {
        anchor.insertAdjacentElement('afterend', nav);
    }
};

const renderPathContinueButton = (main, config, pathOutline) => {
    const target = findPathContinueTarget(config, pathOutline);
    const previousHref = config.previousUrl || null;
    const nextHref = config.pathNextUrl || (target && target.url) || null;
    const courseHref = config.courseUrl || null;
    if (!previousHref && !courseHref && !nextHref) {
        return;
    }

    if (!document.querySelector('.format-selfstudy-pathcontinue-top')) {
        const topWrapper = document.createElement('nav');
        topWrapper.className = 'format-selfstudy-pathcontinue format-selfstudy-pathcontinue-top';
        topWrapper.setAttribute('aria-label', config.continueLabel || 'Weiterlernen');
        topWrapper.style.display = 'grid';
        topWrapper.style.gridTemplateColumns = 'minmax(0, 2fr) minmax(0, 1fr) minmax(0, 2fr)';

        addPathContinueButton(topWrapper, 'Zurück', previousHref, 'btn-secondary');
        addPathContinueButton(topWrapper, config.courseLabel || 'Zum Kurs', courseHref, 'btn-secondary');
        addPathContinueButton(topWrapper, 'Weiter', nextHref, 'btn-primary');

        const pageHeader = document.querySelector('#page-header');
        if (pageHeader) {
            pageHeader.insertAdjacentElement('afterend', topWrapper);
        } else {
            main.prepend(topWrapper);
        }
    }

    if (!document.querySelector('.format-selfstudy-pathcontinue-bottom')) {
        const bottomWrapper = document.createElement('nav');
        bottomWrapper.className = 'format-selfstudy-pathcontinue format-selfstudy-pathcontinue-bottom';
        bottomWrapper.setAttribute('aria-label', config.continueLabel || 'Weiterlernen');
        bottomWrapper.style.display = 'grid';
        bottomWrapper.style.gridTemplateColumns = 'minmax(0, 1fr) minmax(0, 1fr)';

        addPathContinueButton(bottomWrapper, 'Zurück', previousHref, 'btn-secondary');
        addPathContinueButton(bottomWrapper, 'Weiter', nextHref, 'btn-primary');
        main.appendChild(bottomWrapper);
    }
};

const addPathContinueButton = (wrapper, label, href, variant) => {
    const button = document.createElement(href ? 'a' : 'span');
    button.className = `btn ${variant} format-selfstudy-pathcontinue-button`;
    button.textContent = label;
    button.style.width = '100%';
    button.style.minWidth = '0';
    if (variant === 'btn-primary') {
        applyPrimaryButtonColour(button);
    }

    if (href) {
        button.href = href;
    } else {
        button.classList.add('disabled');
        button.setAttribute('aria-disabled', 'true');
    }

    wrapper.appendChild(button);
};

const applyBaseExperienceColours = (config) => {
    const target = document.body || document.documentElement;
    target.style.setProperty('--format-selfstudy-path-color', config.pathPointColor || '#6f1ab1');
    target.style.setProperty('--format-selfstudy-next-button-color',
        config.nextButtonColor || config.pathPointColor || '#6f1ab1');
};

const applyPrimaryButtonColour = (button, color = null) => {
    const primaryColor = color ||
        (document.body ? document.body.style.getPropertyValue('--format-selfstudy-next-button-color') : '') ||
        '#6f1ab1';
    button.style.borderColor = primaryColor;
    button.style.backgroundColor = primaryColor;
    button.style.color = '#fff';
};

const hideActivityCompletionNotice = () => {
    document.querySelectorAll('.activity-header, .activity-information, .completion-info, .automatic-completion-conditions')
        .forEach((element) => {
            element.setAttribute('hidden', 'hidden');
        });
};

const alignActivityIconWithTitle = () => {
    const header = document.querySelector('#page-header .page-context-header');
    const image = document.querySelector('#page-header .page-header-image');
    const headings = document.querySelector('#page-header .page-header-headings');
    const headerColumn = document.querySelector('#page-header .me-auto.d-flex.flex-column');
    const headerRow = document.querySelector('#page-header .d-flex.align-items-center');

    if (!header || !image || !headings) {
        return;
    }

    if (headerRow) {
        headerRow.style.width = '100%';
    }
    if (headerColumn) {
        headerColumn.style.flex = '1 1 auto';
        headerColumn.style.width = '100%';
        headerColumn.style.minWidth = '0';
    }

    header.style.display = 'block';
    header.style.overflow = 'visible';
    header.style.width = '100%';
    image.style.float = 'left';
    image.style.margin = '0 .75rem .25rem 0';
    headings.style.display = 'block';
    headings.style.minWidth = '0';
    headings.style.width = '100%';
};

const findPathContinueTarget = (config, pathOutline) => {
    const stations = pathOutline.filter((entry) => parseInt(entry.cmid || 0, 10) > 0 && entry.url);
    if (!stations.length) {
        return config.completionUrl ? {
            url: config.completionUrl,
            title: config.completionTitle || '',
            completion: true
        } : null;
    }

    const next = stations.find((entry) =>
        !['complete', 'locked', 'missing'].includes(entry.status || 'open'));
    if (next) {
        return next;
    }

    return config.completionUrl ? {
        url: config.completionUrl,
        title: config.completionTitle || '',
        completion: true
    } : null;
};

const renderActivityPath = (main, config, pathOutline) => {
    if (document.querySelector('.format-selfstudy-activitypath')) {
        return;
    }
    if (document.body.classList.contains('format-selfstudy-gamemap-mode') ||
            document.body.classList.contains('format-selfstudy-learningmap-fullscreen') ||
            document.body.classList.contains('path-mod-learningmap') ||
            window.location.pathname.indexOf('/mod/learningmap/') !== -1) {
        return;
    }

    const aside = document.createElement('aside');
    aside.className = 'format-selfstudy-activitypath';
    aside.id = 'format-selfstudy-activitypath';
    aside.setAttribute('aria-label', config.pathTitle || 'Mein Lernpfad');
    aside.style.setProperty('--format-selfstudy-path-color', config.pathPointColor || '#6f1ab1');

    const title = document.createElement('h2');
    title.textContent = config.pathTitle || 'Mein Lernpfad';
    aside.appendChild(title);

    const list = document.createElement('ol');
    list.className = 'format-selfstudy-activitypath-list';
    list.setAttribute('data-format-selfstudy-outline', '1');
    list.setAttribute('aria-label', config.pathTitle || 'Mein Lernpfad');
    const currentCmId = parseInt(config.currentCmId || 0, 10);

    pathOutline.forEach((entry) => {
        const item = document.createElement('li');
        const status = entry.status === 'complete' ? 'complete' :
            currentCmId && parseInt(entry.cmid || 0, 10) === currentCmId ? 'current' :
            (entry.status || 'open');
        item.className = `format-selfstudy-activitypath-item format-selfstudy-activitypath-${status}` +
            ` format-selfstudy-activitypath-type-${entry.type || 'item'}`;
        if (entry.milestoneChild) {
            item.classList.add('format-selfstudy-activitypath-milestonechild');
        }
        if (entry.milestoneGroupStart) {
            item.classList.add('format-selfstudy-activitypath-groupstart');
        }
        if (entry.milestoneGroupEnd) {
            item.classList.add('format-selfstudy-activitypath-groupend');
        }
        if (entry.milestoneComplete) {
            item.classList.add('format-selfstudy-activitypath-milestonecomplete');
        }
        item.style.setProperty('--format-selfstudy-path-level', parseInt(entry.level || 0, 10));
        item.tabIndex = 0;
        item.setAttribute('data-format-selfstudy-outline-item', '1');
        item.setAttribute('aria-label', entry.ariaLabel || buildPathItemAriaLabel(entry, status));

        const dot = document.createElement('span');
        dot.className = 'format-selfstudy-activitypath-dot';
        dot.setAttribute('aria-hidden', 'true');
        if (status !== 'complete' && entry.iconUrl) {
            const icon = document.createElement('img');
            icon.className = 'format-selfstudy-activitypath-icon';
            icon.src = entry.iconUrl;
            icon.alt = '';
            dot.appendChild(icon);
        }
        item.appendChild(dot);

        const label = entry.url ? document.createElement('a') : document.createElement('span');
        label.className = 'format-selfstudy-activitypath-title';
        label.textContent = entry.title || '';
        if (entry.url) {
            label.href = entry.url;
        }
        item.appendChild(label);

        const displayStatusLabel = status === 'current' ? (config.currentStatusLabel || entry.statusLabel || status) :
            (entry.statusLabel || status);
        const ariaEntry = Object.assign({}, entry, {
            statusLabel: displayStatusLabel,
            competenciesLabel: config.competenciesLabel || 'Competencies'
        });
        item.setAttribute('aria-label', buildPathItemAriaLabel(ariaEntry, status));
        const statusLabel = document.createElement('span');
        statusLabel.className = 'format-selfstudy-activitypath-status';
        statusLabel.textContent = displayStatusLabel;
        item.appendChild(statusLabel);

        if (entry.availableInfo) {
            const info = document.createElement('span');
            info.className = 'format-selfstudy-activitypath-info';
            info.textContent = entry.availableInfo;
            item.appendChild(info);
        }
        if (entry.competencies && entry.competencies.length) {
            const competencies = document.createElement('span');
            competencies.className = 'format-selfstudy-activitypath-info format-selfstudy-activitypath-competencies';
            competencies.textContent = `${config.competenciesLabel || 'Competencies'}: ${entry.competencies.join(', ')}`;
            item.appendChild(competencies);
        }

        if (entry.actionUrl && entry.actionLabel) {
            const action = document.createElement('a');
            action.className = 'format-selfstudy-activitypath-action';
            action.href = entry.actionUrl;
            action.textContent = entry.actionLabel;
            item.appendChild(action);
        }

        list.appendChild(item);
    });

    aside.appendChild(list);
    initAccessibleOutlineKeyboard();

    const courseIndex = findCourseIndex();
    if (courseIndex) {
        mountPathInCourseIndex(courseIndex, aside);
        document.body.classList.add('format-selfstudy-has-courseindexpath');
        forceCourseIndexOpen();
        relabelCourseIndexControls(config.pathTitle || 'Mein Lernpfad');
        return;
    }

    const wrapper = document.createElement('div');
    wrapper.className = 'format-selfstudy-activitylayout';
    main.insertAdjacentElement('beforebegin', wrapper);
    wrapper.appendChild(aside);
    wrapper.appendChild(main);
    document.body.classList.add('format-selfstudy-has-activitypath');
};

const buildPathItemAriaLabel = (entry, status) => {
    const parts = [entry.title || '', entry.statusLabel || status || ''];
    if (entry.availableInfo) {
        parts.push(entry.availableInfo);
    }
    if (entry.competencies && entry.competencies.length) {
        parts.push(`${entry.competenciesLabel || 'Competencies'}: ${entry.competencies.join(', ')}`);
    }
    return parts.filter(Boolean).join('. ');
};

const normaliseHexColor = (color) => {
    const value = String(color || '').trim();
    return /^#[0-9a-fA-F]{6}$/.test(value) ? value.toLowerCase() : '#6f1ab1';
};

const initAccessibleOutlineKeyboard = () => {
    document.querySelectorAll('[data-format-selfstudy-outline]').forEach((list) => {
        if (list.dataset.formatSelfstudyKeyboardReady === '1') {
            return;
        }
        list.dataset.formatSelfstudyKeyboardReady = '1';
        list.addEventListener('keydown', (event) => {
            const current = event.target.closest('[data-format-selfstudy-outline-item]');
            if (!current || !list.contains(current)) {
                return;
            }
            const items = Array.from(list.querySelectorAll('[data-format-selfstudy-outline-item]'));
            const index = items.indexOf(current);
            if (index === -1) {
                return;
            }

            let target = null;
            if (event.key === 'ArrowDown') {
                target = items[Math.min(items.length - 1, index + 1)];
            } else if (event.key === 'ArrowUp') {
                target = items[Math.max(0, index - 1)];
            } else if (event.key === 'Home') {
                target = items[0];
            } else if (event.key === 'End') {
                target = items[items.length - 1];
            } else if (event.key === 'Enter' || event.key === ' ') {
                const link = current.querySelector('a[href]');
                if (link) {
                    event.preventDefault();
                    link.click();
                }
                return;
            }

            if (target && target !== current) {
                event.preventDefault();
                target.focus();
            }
        });
    });
};

const findCourseIndex = () => {
    const selectors = [
        '#courseindex',
        '#courseindex-content',
        '[data-region="courseindex"]',
        '[data-region="drawer"] [data-region="courseindex"]',
        '[data-region="drawer"] .courseindex',
        '.courseindex',
    ];

    for (const selector of selectors) {
        const element = document.querySelector(selector);
        if (element && !element.closest('.format-selfstudy-activitypath')) {
            return element;
        }
    }

    return null;
};

const mountPathInCourseIndex = (courseIndex, aside) => {
    const target = courseIndex.id === 'courseindex-content' ? courseIndex.parentElement : courseIndex;
    if (!target) {
        return;
    }

    const mount = () => {
        if (!aside.isConnected || aside.parentElement !== target) {
            aside.classList.add('format-selfstudy-activitypath-courseindex');
            target.prepend(aside);
        }
    };

    mount();
    [250, 750, 1500, 3000].forEach((delay) => window.setTimeout(mount, delay));

    if (!target.dataset.selfstudyPathObserverBound) {
        target.dataset.selfstudyPathObserverBound = '1';
        const observer = new MutationObserver(mount);
        observer.observe(target, {childList: true});
    }
};

const forceCourseIndexOpen = () => {
    const drawer = document.getElementById('theme_boost-drawers-courseindex') ||
        document.querySelector('.drawer.drawer-left');
    const page = document.getElementById('page');

    if (drawer) {
        if (!drawer.classList.contains('show')) {
            drawer.classList.add('show');
        }
        if (drawer.getAttribute('aria-hidden') !== 'false') {
            drawer.setAttribute('aria-hidden', 'false');
        }
    }
    if (page) {
        page.classList.add('show-drawer-left');
    }
};

const relabelCourseIndexControls = (label) => {
    const replacements = [
        {
            selectors: [
                '#theme_boost-drawers-courseindex .drawertoggle',
                '#theme_boost-drawers-courseindex [data-toggler="drawers"]',
            ],
            text: label,
        },
        {
            selectors: [
                '.drawer-left-toggle button',
                '.drawer-left-toggle a',
                '[data-target="theme_boost-drawers-courseindex"]',
                '[data-target="#theme_boost-drawers-courseindex"]',
            ],
            text: `${label} öffnen`,
        },
    ];

    replacements.forEach((group) => {
        group.selectors.forEach((selector) => {
            document.querySelectorAll(selector).forEach((element) => {
                element.setAttribute('title', group.text);
                element.setAttribute('aria-label', group.text);
                const textNode = Array.from(element.childNodes).find((node) =>
                    node.nodeType === Node.TEXT_NODE && node.textContent.trim()
                );
                if (textNode) {
                    textNode.textContent = group.text;
                }
            });
        });
    });
};

const findSecondaryNavigation = (pageHeader, main) => {
    if (!pageHeader || !main) {
        return null;
    }

    let node = pageHeader.nextElementSibling;
    while (node && node !== main) {
        if (node.matches('nav') && !node.classList.contains('format-selfstudy-activitynav')) {
            return node;
        }
        node = node.nextElementSibling;
    }

    return null;
};

const applyGamemapFrameLayout = (iframe, config) => {
    let frameDocument = null;
    try {
        frameDocument = iframe.contentDocument;
    } catch (error) {
        return;
    }

    if (!frameDocument || frameDocument.getElementById('format-selfstudy-gamemap-frame-style')) {
        return;
    }

    const style = frameDocument.createElement('style');
    style.id = 'format-selfstudy-gamemap-frame-style';
    style.textContent = `
        html,
        body {
            width: 100% !important;
            height: 100% !important;
            margin: 0 !important;
            overflow: hidden !important;
            background: #f7fafc !important;
        }

        body > nav,
        .navbar,
        .primary-navigation,
        .secondary-navigation,
        #page-header,
        #page-navbar,
        #courseindex,
        .courseindex,
        .courseindex-section,
        [data-region="courseindex"],
        [data-region="drawer"],
        [data-region="drawer-toggle"],
        [data-region="right-hand-drawer"],
        [data-region="drawer"],
        .drawer,
        .drawercontent,
        .drawer-toggles,
        .block-region,
        aside,
        .activity-navigation,
        .format-selfstudy-activitynav,
        footer,
        #page-footer {
            display: none !important;
        }

        #page,
        #page.drawers,
        #page-content,
        #region-main-box,
        #region-main,
        [role="main"] {
            width: 100vw !important;
            max-width: none !important;
            height: 100vh !important;
            min-height: 100vh !important;
            margin: 0 !important;
            padding: 0 !important;
            border: 0 !important;
            background: transparent !important;
            box-shadow: none !important;
        }

        [role="main"] > *,
        .card,
        .container,
        .container-fluid,
        .generalbox,
        .box,
        .no-overflow {
            width: 100% !important;
            max-width: none !important;
            margin: 0 !important;
            padding: 0 !important;
            border: 0 !important;
            background: transparent !important;
            box-shadow: none !important;
        }

        [role="main"] img,
        [role="main"] canvas,
        [role="main"] svg {
            max-width: none !important;
        }

        [role="main"] img {
            width: 100vw !important;
            height: 100vh !important;
            object-fit: cover !important;
            object-position: center center !important;
        }

        [role="main"] canvas,
        [role="main"] svg {
            width: 100vw !important;
            height: 100vh !important;
        }

        .format-selfstudy-avatar-marker img {
            width: 100% !important;
            height: 100% !important;
            border-radius: 50% !important;
            object-fit: cover !important;
        }
    `;
    frameDocument.head.appendChild(style);
    frameDocument.querySelectorAll('a[target]').forEach((link) => {
        link.removeAttribute('target');
    });
    frameDocument.addEventListener('click', (event) => {
        const link = event.target.closest('a[href]');
        if (!link || !shouldBlockGamemapFrameLink(link.href)) {
            return;
        }

        event.preventDefault();
        event.stopPropagation();
    }, true);

    const frameMap = frameDocument.querySelector('[role="application"]');
    if (frameMap) {
        const activities = [{
            id: parseInt(config.currentActivityId || 0, 10),
            url: window.location.href,
            name: '',
        }];
        if (config.avatarEnabled !== false) {
            initMapAvatarMarker(frameMap, activities, config, frameDocument.defaultView);
        }
    }
};

const applyActivityPopupFrameLayout = (iframe) => {
    let frameDocument = null;
    try {
        frameDocument = iframe.contentDocument;
    } catch (error) {
        return;
    }

    if (!frameDocument || frameDocument.getElementById('format-selfstudy-activity-popup-frame-style')) {
        return;
    }

    const style = frameDocument.createElement('style');
    style.id = 'format-selfstudy-activity-popup-frame-style';
    style.textContent = `
        html,
        body {
            margin: 0 !important;
            background: #ffffff !important;
        }

        .navbar,
        .primary-navigation,
        .secondary-navigation,
        #page-header,
        #page-navbar,
        .drawer,
        .drawer-toggles,
        .activity-navigation,
        #page-footer,
        footer {
            display: none !important;
        }

        #page,
        #page.drawers,
        #page-content,
        #region-main-box,
        #region-main,
        [role="main"] {
            width: 100% !important;
            max-width: none !important;
            min-height: 0 !important;
            margin: 0 !important;
            padding: 0 !important;
            border: 0 !important;
            background: #ffffff !important;
            box-shadow: none !important;
        }

        [role="main"] {
            padding: 1rem 1.25rem 1.5rem !important;
        }

        [role="main"] > nav,
        [role="main"] > .activity-header,
        [role="main"] > .activity-information {
            display: none !important;
        }

        [role="main"] img,
        [role="main"] video,
        [role="main"] canvas,
        [role="main"] iframe {
            max-width: 100% !important;
            box-sizing: border-box !important;
        }
    `;
    frameDocument.head.appendChild(style);
};

const shouldBlockGamemapFrameLink = (href) => {
    let url = null;
    try {
        url = new URL(href, window.location.origin);
    } catch (error) {
        return true;
    }

    const blockedPaths = [
        '/course/view.php',
        '/course/section.php',
        '/user/index.php',
        '/enrol/users.php',
        '/grade/',
        '/report/',
        '/admin/',
        '/badges/',
        '/competency/',
    ];

    return blockedPaths.some((path) => url.pathname.startsWith(path));
};

const initLearningmapFullscreen = (config) => {
    const activities = Array.isArray(config.activityUrls) ? config.activityUrls : [];
    const main = document.querySelector('[role="main"]');
    const map = main ? main.querySelector('[role="application"]') : null;
    if (!main || !map || document.querySelector('.format-selfstudy-fullscreen-toggle')) {
        return;
    }
    if (config.avatarEnabled !== false) {
        initMapAvatarMarker(map, activities, config, window);
    }

    const button = document.createElement('button');
    button.type = 'button';
    button.className = 'btn btn-primary format-selfstudy-fullscreen-toggle';
    button.textContent = 'Vollbild';
    Object.assign(button.style, {
        position: 'fixed',
        top: '5rem',
        right: '.75rem',
        zIndex: '1050',
    });
    document.body.appendChild(button);

    if (config.courseUrl) {
        const courseLink = document.createElement('a');
        courseLink.className = 'btn btn-secondary format-selfstudy-map-course-link';
        courseLink.href = config.courseUrl;
        courseLink.textContent = config.courseLabel || 'Zum Kurs';
        Object.assign(courseLink.style, {
            position: 'fixed',
            top: '8rem',
            right: '.75rem',
            zIndex: '1050',
        });
        document.body.appendChild(courseLink);
    }

    if (config.accessiblePathUrl) {
        const accessibleLink = document.createElement('a');
        accessibleLink.className = 'btn btn-secondary format-selfstudy-accessiblepath-link';
        accessibleLink.href = config.accessiblePathUrl;
        accessibleLink.textContent = config.accessiblePathLabel || 'Barrierearme Lernpfadansicht';
        Object.assign(accessibleLink.style, {
            position: 'fixed',
            top: '11rem',
            right: '.75rem',
            zIndex: '1050',
        });
        document.body.appendChild(accessibleLink);
    }

    const overlay = document.createElement('div');
    overlay.className = 'format-selfstudy-map-popup-overlay';
    overlay.setAttribute('aria-hidden', 'true');

    const popup = document.createElement('div');
    popup.className = 'format-selfstudy-map-popup';
    popup.setAttribute('role', 'dialog');
    popup.setAttribute('aria-modal', 'true');

    const popupHeader = document.createElement('div');
    popupHeader.className = 'format-selfstudy-map-popup-header';

    const popupTitle = document.createElement('div');
    popupTitle.className = 'format-selfstudy-map-popup-title';

    const closePopupButton = document.createElement('button');
    closePopupButton.type = 'button';
    closePopupButton.className = 'btn btn-light format-selfstudy-map-popup-close';
    closePopupButton.textContent = 'Schliessen';
    popupHeader.append(popupTitle, closePopupButton);

    const previousButton = document.createElement('button');
    previousButton.type = 'button';
    previousButton.className = 'format-selfstudy-map-popup-arrow format-selfstudy-map-popup-prev';
    previousButton.setAttribute('aria-label', 'Vorherige Aktivitaet');
    previousButton.textContent = '‹';

    const nextButton = document.createElement('button');
    nextButton.type = 'button';
    nextButton.className = 'format-selfstudy-map-popup-arrow format-selfstudy-map-popup-next';
    nextButton.setAttribute('aria-label', 'Naechste Aktivitaet');
    nextButton.textContent = '›';

    const frame = document.createElement('iframe');
    frame.className = 'format-selfstudy-map-popup-frame';
    frame.setAttribute('title', 'Aktivitaet');
    frame.addEventListener('load', () => {
        applyActivityPopupFrameLayout(frame);
    });

    popup.append(popupHeader, previousButton, frame, nextButton);
    overlay.appendChild(popup);
    document.body.appendChild(overlay);

    let currentIndex = -1;

    const openActivity = (index) => {
        if (index < 0 || index >= activities.length) {
            return;
        }

        currentIndex = index;
        popupTitle.textContent = getActivityDisplayTitle(activities[index]);
        frame.src = activities[index].url;
        overlay.classList.add('format-selfstudy-map-popup-open');
        overlay.setAttribute('aria-hidden', 'false');
        previousButton.disabled = currentIndex <= 0;
        nextButton.disabled = currentIndex >= activities.length - 1;
        closePopupButton.focus();
    };

    const closePopup = () => {
        overlay.setAttribute('aria-hidden', 'true');
        overlay.classList.add('format-selfstudy-map-popup-closing');
        overlay.classList.remove('format-selfstudy-map-popup-open');
        window.setTimeout(() => {
            overlay.classList.remove('format-selfstudy-map-popup-closing');
            if (!overlay.classList.contains('format-selfstudy-map-popup-open')) {
                frame.removeAttribute('src');
                currentIndex = -1;
            }
        }, 240);
    };

    const toggleFullscreen = () => {
        const enabled = !document.body.classList.contains('format-selfstudy-learningmap-fullscreen');
        document.body.classList.toggle('format-selfstudy-learningmap-fullscreen', enabled);
        applyLearningmapFullscreenLayout(enabled, main, map, button);
        button.textContent = enabled ?
            'Vollbild schliessen' : 'Vollbild';
        if (!enabled) {
            closePopup();
        }
    };

    button.addEventListener('click', toggleFullscreen);
    closePopupButton.addEventListener('click', closePopup);
    previousButton.addEventListener('click', () => openActivity(currentIndex - 1));
    nextButton.addEventListener('click', () => openActivity(currentIndex + 1));
    overlay.addEventListener('click', (event) => {
        if (event.target === overlay) {
            closePopup();
        }
    });
    document.addEventListener('keydown', (event) => {
        if (!document.body.classList.contains('format-selfstudy-learningmap-fullscreen')) {
            return;
        }
        if (event.key === 'Escape') {
            if (overlay.classList.contains('format-selfstudy-map-popup-open')) {
                closePopup();
            } else {
                toggleFullscreen();
            }
        }
        if (event.key === 'ArrowLeft' && overlay.classList.contains('format-selfstudy-map-popup-open')) {
            openActivity(currentIndex - 1);
        }
        if (event.key === 'ArrowRight' && overlay.classList.contains('format-selfstudy-map-popup-open')) {
            openActivity(currentIndex + 1);
        }
    });

    map.addEventListener('click', (event) => {
        if (!document.body.classList.contains('format-selfstudy-learningmap-fullscreen')) {
            return;
        }

        const index = findActivityIndex(event.target, activities);
        if (index === -1) {
            return;
        }

        event.preventDefault();
        event.stopPropagation();
        openActivity(index);
    }, true);
};

const getActivityDisplayTitle = (activity) => {
    const name = activity.name || 'Aktivitaet';
    return activity.completionLabel ? `${name} - ${activity.completionLabel}` : name;
};

const findActivityIndex = (target, activities) => {
    const link = target.closest ? target.closest('a[href]') : null;
    if (link) {
        const id = getCmIdFromUrl(link.href);
        const linkIndex = activities.findIndex((activity) => activity.id === id || activity.url === link.href);
        if (linkIndex !== -1) {
            return linkIndex;
        }
    }

    let node = target;
    while (node && node.nodeType === Node.ELEMENT_NODE) {
        const label = normalizeActivityLabel([
            node.getAttribute('aria-label'),
            node.getAttribute('title'),
            node.textContent,
        ].filter(Boolean).join(' '));

        if (label) {
            const index = activities.findIndex((activity) => label.indexOf(normalizeActivityLabel(activity.name)) !== -1);
            if (index !== -1) {
                return index;
            }
        }
        node = node.parentElement;
    }

    return -1;
};

const initMapAvatarMarker = (map, activities, config, targetWindow) => {
    const currentActivityId = getLastCompletedActivityId(activities) || parseInt(config.currentActivityId || 0, 10);
    const markerHost = getAvatarMarkerHost(map, targetWindow);
    if (!currentActivityId || !markerHost || markerHost.querySelector('.format-selfstudy-avatar-marker')) {
        return;
    }
    applyActivityCompletionStatuses(map, activities);

    const marker = createAvatarMarker(config, map.ownerDocument);
    const connector = map.ownerDocument.createElement('div');
    connector.className = 'format-selfstudy-avatar-connector';
    const ring = map.ownerDocument.createElement('div');
    ring.className = 'format-selfstudy-avatar-target-ring';
    const usesBodyHost = markerHost === map.ownerDocument.body;
    marker.hidden = true;
    connector.hidden = true;
    ring.hidden = true;
    markerHost.append(connector, ring);
    markerHost.appendChild(marker);

    if (targetWindow.getComputedStyle(markerHost).position === 'static') {
        markerHost.dataset.selfstudyAvatarPreviousPosition = markerHost.style.position || '';
        markerHost.style.position = 'relative';
    }

    const placeMarker = () => {
        const target = findActivityElement(map, currentActivityId, activities);
        if (!target) {
            marker.hidden = true;
            connector.hidden = true;
            ring.hidden = true;
            return;
        }

        const targetRect = target.getBoundingClientRect();
        const usesViewportCoordinates = usesBodyHost &&
            map.ownerDocument.body.classList.contains('format-selfstudy-learningmap-fullscreen');
        const mapRect = usesViewportCoordinates ? {
            left: 0,
            top: 0,
            width: targetWindow.innerWidth,
            height: targetWindow.innerHeight,
        } : markerHost.getBoundingClientRect();
        if (!mapRect.width || !mapRect.height || !targetRect.width || !targetRect.height) {
            marker.hidden = true;
            connector.hidden = true;
            ring.hidden = true;
            return;
        }

        marker.classList.toggle('format-selfstudy-avatar-viewport-overlay', usesViewportCoordinates);
        connector.classList.toggle('format-selfstudy-avatar-viewport-overlay', usesViewportCoordinates);
        ring.classList.toggle('format-selfstudy-avatar-viewport-overlay', usesViewportCoordinates);

        const x = targetRect.left - mapRect.left + (targetRect.width / 2);
        const y = targetRect.top - mapRect.top + (targetRect.height / 2);
        const markerSize = Math.min(marker.offsetWidth || 34, 42);
        const markerHalf = markerSize / 2;
        const offset = 28;
        const markerX = Math.max(markerHalf, Math.min(mapRect.width - markerHalf, x + offset));
        const markerY = Math.max(markerHalf, Math.min(mapRect.height - markerHalf, y - offset));
        const connectorX = x;
        const connectorY = y;
        const connectorLength = Math.hypot(markerX - connectorX, markerY - connectorY);
        const connectorAngle = Math.atan2(markerY - connectorY, markerX - connectorX) * 180 / Math.PI;

        marker.hidden = false;
        connector.hidden = false;
        ring.hidden = false;
        marker.style.left = `${markerX}px`;
        marker.style.top = `${markerY}px`;
        connector.style.left = `${connectorX}px`;
        connector.style.top = `${connectorY}px`;
        connector.style.width = `${connectorLength}px`;
        connector.style.transform = `rotate(${connectorAngle}deg)`;
        ring.style.left = `${connectorX}px`;
        ring.style.top = `${connectorY}px`;
    };

    targetWindow.requestAnimationFrame(placeMarker);
    targetWindow.setTimeout(placeMarker, 300);
    targetWindow.addEventListener('resize', placeMarker);
    targetWindow.addEventListener('scroll', placeMarker, {passive: true});
    targetWindow.addEventListener('format-selfstudy-map-layoutchange', () => {
        targetWindow.requestAnimationFrame(placeMarker);
        targetWindow.setTimeout(placeMarker, 120);
        targetWindow.setTimeout(placeMarker, 360);
    });
    if (targetWindow.ResizeObserver) {
        const observer = new targetWindow.ResizeObserver(placeMarker);
        observer.observe(map);
        marker.selfstudyResizeObserver = observer;
    }
};

const applyActivityCompletionStatuses = (map, activities) => {
    activities.forEach((activity) => {
        const link = findActivityDataLink(map, activity.id);
        if (!link) {
            return;
        }

        const place = getLinkedLearningmapPlace(map, link) || link;
        const status = activity.completionStatus || 'available';
        const label = activity.completionLabel || status;
        const title = `${activity.name || ''}: ${label}`.trim();

        link.dataset.selfstudyCompletionStatus = status;
        place.dataset.selfstudyCompletionStatus = status;
        place.classList.remove(
            'format-selfstudy-status-complete',
            'format-selfstudy-status-notstarted',
            'format-selfstudy-status-available'
        );
        place.classList.add(`format-selfstudy-status-${status}`);

        if (title) {
            const titleNode = link.querySelector('title') || place.querySelector('title');
            if (titleNode) {
                titleNode.textContent = title;
            } else {
                link.setAttribute('aria-label', title);
            }
        }
    });
};

const getLastCompletedActivityId = (activities) => {
    const completed = activities
        .filter((activity) => activity.completionStatus === 'complete' && parseInt(activity.completionTime || 0, 10) > 0)
        .sort((left, right) => parseInt(right.completionTime || 0, 10) - parseInt(left.completionTime || 0, 10));

    return completed.length ? parseInt(completed[0].id || 0, 10) : 0;
};

const getAvatarMarkerHost = (map, targetWindow) => {
    if (map instanceof targetWindow.HTMLElement &&
            !['CANVAS', 'IMG', 'SVG'].includes(map.tagName.toUpperCase())) {
        return map;
    }

    return map.ownerDocument.body || map.parentElement || null;
};

const createAvatarMarker = (config, ownerDocument) => {
    const marker = ownerDocument.createElement('div');
    marker.className = 'format-selfstudy-avatar-marker';
    marker.setAttribute('role', 'img');
    marker.setAttribute('aria-label', config.avatarLabel || 'Aktuelle Position');

    if (config.avatarImageUrl) {
        const image = ownerDocument.createElement('img');
        image.src = config.avatarImageUrl;
        image.alt = '';
        image.decoding = 'async';
        marker.appendChild(image);
    } else {
        const fallback = ownerDocument.createElement('span');
        fallback.textContent = getInitial(config.avatarLabel);
        marker.appendChild(fallback);
    }

    return marker;
};

const findActivityElement = (map, currentActivityId, activities) => {
    const activity = activities.find((item) => parseInt(item.id || 0, 10) === currentActivityId) || {};
    const dataLink = findActivityDataLink(map, currentActivityId);
    if (dataLink) {
        const linkedPlace = getLinkedLearningmapPlace(map, dataLink);
        return linkedPlace || dataLink;
    }

    const links = Array.from(map.querySelectorAll('a[href]'));
    const link = links.find((candidate) => getCmIdFromUrl(candidate.href) === currentActivityId ||
        (activity.url && urlsMatch(candidate.href, activity.url)));
    if (link) {
        return link;
    }

    const targetPlace = findLearningmapTargetPlace(map);
    if (targetPlace) {
        return targetPlace;
    }

    const label = normalizeActivityLabel(activity.name);
    if (!label) {
        return null;
    }

    return Array.from(map.querySelectorAll('[aria-label], [title], text, button, [role="button"]')).find((node) => {
        const nodeLabel = normalizeActivityLabel([
            node.getAttribute('aria-label'),
            node.getAttribute('title'),
            node.textContent,
        ].filter(Boolean).join(' '));
        return nodeLabel && nodeLabel.indexOf(label) !== -1;
    }) || null;
};

const findActivityDataLink = (map, activityId) => Array.from(map.querySelectorAll('[data-cmid]')).find((candidate) =>
    parseInt(candidate.getAttribute('data-cmid') || 0, 10) === parseInt(activityId || 0, 10));

const getLinkedLearningmapPlace = (map, link) => link.querySelector('.learningmap-place') ||
    map.querySelector(`#p${String(link.id || '').replace(/^a/, '')}`);

const findLearningmapTargetPlace = (map) => {
    const places = Array.from(map.querySelectorAll('.learningmap-targetplace, .learningmap-place'));
    const visiblePlaces = places.filter((place) => {
        const styles = place.ownerDocument.defaultView.getComputedStyle(place);
        const rect = place.getBoundingClientRect();
        return styles.visibility !== 'hidden' && styles.display !== 'none' &&
            styles.opacity !== '0' && rect.width > 0 && rect.height > 0;
    });
    if (!visiblePlaces.length) {
        return null;
    }

    const targetPlaces = visiblePlaces.filter((place) => place.classList.contains('learningmap-targetplace'));
    const redTargetPlace = targetPlaces.find(isLearningmapOpenPlace);
    const openPlace = visiblePlaces.find(isLearningmapOpenPlace);

    return targetPlaces[0] || redTargetPlace || openPlace || visiblePlaces[0];
};

const isLearningmapOpenPlace = (place) => {
    const fill = place.ownerDocument.defaultView.getComputedStyle(place).fill;
    return /rgb\(\s*192\s*,\s*28\s*,\s*40\s*\)|#c01c28/i.test(fill);
};

const applyLearningmapFullscreenLayout = (enabled, main, map, button) => {
    const hiddenSelectors = [
        '.navbar',
        '.primary-navigation',
        '.secondary-navigation',
        '#page-header',
        '#page-navbar',
        '.drawer',
        '.drawer-toggles',
        '.activity-navigation',
        '#page-footer',
        'footer',
    ];
    const fullSelectors = [
        '#page',
        '#page-content',
        '#region-main-box',
        '#region-main',
    ];

    document.body.style.overflow = enabled ? 'hidden' : '';
    document.body.style.background = enabled ? '#0f172a' : '';
    Object.assign(button.style, {
        top: enabled ? '.75rem' : '5rem',
        right: '.75rem',
        zIndex: '1050',
    });

    hiddenSelectors.forEach((selector) => {
        document.querySelectorAll(selector).forEach((node) => {
            if (!node.dataset.selfstudyPreviousDisplay) {
                node.dataset.selfstudyPreviousDisplay = node.style.display || ' ';
            }
            node.style.display = enabled ? 'none' : node.dataset.selfstudyPreviousDisplay.trim();
            if (!enabled) {
                delete node.dataset.selfstudyPreviousDisplay;
            }
        });
    });

    fullSelectors.forEach((selector) => {
        document.querySelectorAll(selector).forEach((node) => {
            if (enabled) {
                Object.assign(node.style, {
                    position: 'fixed',
                    inset: '0',
                    width: '100vw',
                    maxWidth: 'none',
                    height: '100vh',
                    minHeight: '100vh',
                    margin: '0',
                    padding: '0',
                    border: '0',
                    background: '#0f172a',
                    boxShadow: 'none',
                    overflow: 'hidden',
                });
            } else {
                [
                    'position', 'inset', 'width', 'maxWidth', 'height', 'minHeight', 'margin', 'padding',
                    'border', 'background', 'boxShadow', 'overflow',
                ].forEach((property) => {
                    node.style[property] = '';
                });
            }
        });
    });

    if (enabled) {
        Object.assign(main.style, {
            position: 'fixed',
            inset: '0',
            width: '100vw',
            maxWidth: 'none',
            height: '100vh',
            margin: '0',
            padding: '0',
            background: '#0f172a',
            overflow: 'hidden',
        });
        Object.assign(map.style, {
            display: 'block',
            visibility: 'visible',
            position: 'fixed',
            inset: '0',
            zIndex: '2',
            width: '100vw',
            maxWidth: 'none',
            height: '100vh',
            margin: '0',
            padding: '0',
            overflow: 'hidden',
        });
        map.querySelectorAll('img, image, canvas, svg').forEach((node) => {
            node.style.maxWidth = 'none';
        });
    } else {
        [
            'position', 'inset', 'width', 'maxWidth', 'height', 'margin', 'padding', 'background', 'overflow',
        ].forEach((property) => {
            main.style[property] = '';
        });
        [
            'display', 'visibility', 'position', 'inset', 'zIndex', 'width', 'maxWidth', 'height', 'margin',
            'padding', 'overflow',
        ].forEach((property) => {
            map.style[property] = '';
        });
        map.querySelectorAll('img, image, canvas, svg').forEach((node) => {
            node.style.maxWidth = '';
        });
    }
    window.dispatchEvent(new Event('format-selfstudy-map-layoutchange'));
};

const getCmIdFromUrl = (href) => {
    try {
        return parseInt(new URL(href, window.location.origin).searchParams.get('id'), 10);
    } catch (error) {
        return 0;
    }
};

const urlsMatch = (left, right) => {
    try {
        return new URL(left, window.location.origin).href === new URL(right, window.location.origin).href;
    } catch (error) {
        return left === right;
    }
};

const getInitial = (value) => {
    const label = String(value || '').replace(/^.*?:\s*/, '').trim();
    return label ? label.charAt(0).toUpperCase() : '*';
};

const normalizeActivityLabel = (value) => String(value || '')
    .replace(/\s+/g, ' ')
    .replace(/\(Zielort\)/gi, '')
    .trim()
    .toLowerCase();


    exports.init = init;
});
